; パーツ画像
━ = stone
　 = marble
／ = door
∫ = pick
㊤ = ladderu
㊦ = ladderd
⑴ = barrel
⑵ = br_int

; 敵情報
maxGroups = 3
monsters = パイレーツ,キャプテン,ブッシュワッカー,バーグラー

[map]
